   290→          fleetCount: 128,
   291→          totalPmScheduled: 456,
   292→          totalManhourProjected: '12500.50',
   293→          createdAt: new Date(),
   294→          publishedAt: new Date(),
   295→        };
   296→        expect(summary.id).toBe('baseline-123');
   297→        expect(summary.version).toBe('v2.5');
   298→        expect(summary.status).toBe('PUBLISHED');
   299→        expect(summary.fleetCount).toBe(128);
   300→      });
   301→
   302→      test('should allow null values for metrics', () => {
   303→        const summary: BaselineSummary = {
   304→          id: 'baseline-draft',
   305→          name: 'Draft Plan',
   306→          version: 'v1.0',
   307→          status: 'DRAFT',
   308→          baselineDate: '2026-01-20',
   309→          horizonEnd: '2036-01-20',
   310→          fleetCount: null,
   311→          totalPmScheduled: null,
   312→          totalManhourProjected: null,
   313→          createdAt: null,
   314→          publishedAt: null,
   315→        };
   316→        expect(summary.fleetCount).toBeNull();
   317→        expect(summary.totalPmScheduled).toBeNull();
   318→      });
   319→    });
   320→  });
   321→
   322→  describe('Business Rules', () => {
   323→    describe('Version Incrementing', () => {
   324→      // The incrementVersion function increments vMajor.Minor format
   325→      const incrementVersion = (current: string | null): string => {
   326→        if (!current) {
   327→          return 'v1.0';
   328→        }
   329→        const match = current.match(/^v?(\d+)\.(\d+)$/);
   330→        if (!match) {
   331→          return 'v1.0';
   332→        }
   333→        const major = parseInt(match[1], 10);
   334→        const minor = parseInt(match[2], 10);
   335→        if (minor >= 99) {
   336→          return `v${major + 1}.0`;
   337→        }
   338→        return `v${major}.${minor + 1}`;
   339→      };
   340→
   341→      test('should start at v1.0 when no previous version', () => {
   342→        expect(incrementVersion(null)).toBe('v1.0');
   343→      });
   344→
   345→      test('should increment minor version v1.0 -> v1.1', () => {
   346→        expect(incrementVersion('v1.0')).toBe('v1.1');
   347→      });
   348→
   349→      test('should increment minor version v1.5 -> v1.6', () => {
   350→        expect(incrementVersion('v1.5')).toBe('v1.6');
   351→      });
   352→
   353→      test('should increment minor version v2.10 -> v2.11', () => {
   354→        expect(incrementVersion('v2.10')).toBe('v2.11');
   355→      });
   356→
   357→      test('should roll over to next major at v1.99 -> v2.0', () => {
   358→        expect(incrementVersion('v1.99')).toBe('v2.0');
   359→      });
   360→
   361→      test('should roll over to next major at v5.99 -> v6.0', () => {
   362→        expect(incrementVersion('v5.99')).toBe('v6.0');
   363→      });
   364→
   365→      test('should handle version without v prefix', () => {
   366→        expect(incrementVersion('1.5')).toBe('v1.6');
   367→      });
   368→
   369→      test('should default to v1.0 for invalid format', () => {
   370→        expect(incrementVersion('invalid')).toBe('v1.0');
   371→        expect(incrementVersion('v1')).toBe('v1.0');
   372→        expect(incrementVersion('1.2.3')).toBe('v1.0');
   373→      });
   374→    });
   375→
   376→    describe('Baseline Lifecycle', () => {
   377→      test('DRAFT baselines can transition to PUBLISHED', () => {
   378→        // Draft -> Published is the normal publication flow
   379→        const validTransitions: Record<BaselineStatus, BaselineStatus[]> = {
   380→          DRAFT: ['PUBLISHED'],
   381→          PUBLISHED: ['SUPERSEDED', 'ARCHIVED'],
   382→          SUPERSEDED: ['ARCHIVED'],
   383→          ARCHIVED: [],
   384→        };
   385→        expect(validTransitions['DRAFT']).toContain('PUBLISHED');
   386→      });
   387→
   388→      test('PUBLISHED baselines can be SUPERSEDED or ARCHIVED', () => {
   389→        const validTransitions: Record<BaselineStatus, BaselineStatus[]> = {
   390→          DRAFT: ['PUBLISHED'],
   391→          PUBLISHED: ['SUPERSEDED', 'ARCHIVED'],
   392→          SUPERSEDED: ['ARCHIVED'],
   393→          ARCHIVED: [],
   394→        };
   395→        expect(validTransitions['PUBLISHED']).toContain('SUPERSEDED');
   396→        expect(validTransitions['PUBLISHED']).toContain('ARCHIVED');
   397→      });
   398→
   399→      test('SUPERSEDED baselines can only be ARCHIVED', () => {
   400→        const validTransitions: Record<BaselineStatus, BaselineStatus[]> = {
   401→          DRAFT: ['PUBLISHED'],
   402→          PUBLISHED: ['SUPERSEDED', 'ARCHIVED'],
   403→          SUPERSEDED: ['ARCHIVED'],
   404→          ARCHIVED: [],
   405→        };
   406→        expect(validTransitions['SUPERSEDED']).toEqual(['ARCHIVED']);
   407→      });
   408→
   409→      test('ARCHIVED baselines cannot transition', () => {
   410→        const validTransitions: Record<BaselineStatus, BaselineStatus[]> = {
   411→          DRAFT: ['PUBLISHED'],
   412→          PUBLISHED: ['SUPERSEDED', 'ARCHIVED'],
   413→          SUPERSEDED: ['ARCHIVED'],
   414→          ARCHIVED: [],
   415→        };
   416→        expect(validTransitions['ARCHIVED']).toHaveLength(0);
   417→      });
   418→    });
   419→
   420→    describe('Plan Validation Rules', () => {
   421→      test('should fail validation if any PM is overdue', () => {
   422→        const checkOverduePms = (pms: Array<{ constraintEnd: Date; status: string }>) => {
   423→          const today = new Date();
   424→          return pms.filter(
   425→            (pm) => pm.status === 'SCHEDULED' && pm.constraintEnd < today
   426→          );
   427→        };
   428→
   429→        const pms = [
   430→          { constraintEnd: new Date('2025-12-31'), status: 'SCHEDULED' }, // Overdue
   431→          { constraintEnd: new Date('2026-02-15'), status: 'SCHEDULED' }, // OK
   432→        ];
   433→
   434→        const overdue = checkOverduePms(pms);
   435→        expect(overdue).toHaveLength(1);
   436→      });
   437→
   438→      test('should fail validation if grounded train has scheduled PMs', () => {
   439→        interface Train { id: string; fitnessStatus: string; }
   440→        interface PM { trainId: string; status: string; }
   441→
   442→        const validate = (trains: Train[], pms: PM[]) => {
   443→          const groundedTrainIds = trains
   444→            .filter((t) => t.fitnessStatus === 'GROUNDED')
   445→            .map((t) => t.id);
   446→
   447→          return pms.filter(
   448→            (pm) =>
   449→              pm.status === 'SCHEDULED' && groundedTrainIds.includes(pm.trainId)
   450→          );
   451→        };
   452→
   453→        const trains = [
   454→          { id: 'train-1', fitnessStatus: 'FIT' },
   455→          { id: 'train-2', fitnessStatus: 'GROUNDED' },
   456→        ];
   457→
   458→        const pms = [
   459→          { trainId: 'train-1', status: 'SCHEDULED' },
   460→          { trainId: 'train-2', status: 'SCHEDULED' }, // Invalid
   461→        ];
   462→
   463→        const invalid = validate(trains, pms);
   464→        expect(invalid).toHaveLength(1);
   465→        expect(invalid[0].trainId).toBe('train-2');
   466→      });
   467→
   468→      test('should allow publishing with warnings but no conflicts', () => {
   469→        const canPublish = (result: PlanValidationResult) => result.valid;
   470→
   471→        const resultWithWarnings: PlanValidationResult = {
   472→          valid: true,
   473→          conflicts: [],
   474→          warnings: [{ type: 'LOW_MATERIAL', description: 'Low stock' }],
   475→        };
   476→
   477→        expect(canPublish(resultWithWarnings)).toBe(true);
   478→      });
   479→
   480→      test('should not allow publishing with conflicts', () => {
   481→        const canPublish = (result: PlanValidationResult) => result.valid;
   482→
   483→        const resultWithConflicts: PlanValidationResult = {
   484→          valid: false,
   485→          conflicts: [{ type: 'OVERDUE_PM', description: 'PM overdue' }],
   486→          warnings: [],
   487→        };
   488→
   489→        expect(canPublish(resultWithConflicts)).toBe(false);
   490→      });
   491→    });
   492→
   493→    describe('Mileage Projection Rules', () => {
   494→      test('should use 30-day average when history available', () => {
   495→        const dailyReadings = [300, 280, 320, 290, 310, 305, 295];
   496→        const avg = dailyReadings.reduce((a, b) => a + b, 0) / dailyReadings.length;
   497→
   498→        expect(avg).toBeCloseTo(300);
   499→      });
   500→
   501→      test('should use default 150km when no history', () => {
   502→        const DEFAULT_DAILY_KM = 150;
   503→        const dailyReadings: number[] = [];
   504→
   505→        const avgDailyKm =
   506→          dailyReadings.length > 0
   507→            ? dailyReadings.reduce((a, b) => a + b, 0) / dailyReadings.length
   508→            : DEFAULT_DAILY_KM;
   509→
   510→        expect(avgDailyKm).toBe(150);
   511→      });
   512→
   513→      test('should project monthly cumulative mileage', () => {
   514→        const currentKm = 100000;
   515→        const avgDailyKm = 300;
   516→        const months = 3;
   517→
   518→        // Monthly projections with explicit type
   519→        const projections: Array<{ month: number; km: number }> = [];
   520→        let cumulative = currentKm;
   521→
   522→        for (let m = 1; m <= months; m++) {
   523→          cumulative += avgDailyKm * 30;
   524→          projections.push({ month: m, km: cumulative });
   525→        }
   526→
   527→        expect(projections).toHaveLength(3);
   528→        expect(projections[0].km).toBe(109000); // 100000 + 9000
   529→        expect(projections[1].km).toBe(118000); // 100000 + 18000
   530→        expect(projections[2].km).toBe(127000); // 100000 + 27000
   531→      });
   532→
   533→      test('should project for default 10 years (120 months)', () => {
   534→        const DEFAULT_HORIZON_YEARS = 10;
   535→        const MONTHS_PER_YEAR = 12;
   536→        const expectedProjections = DEFAULT_HORIZON_YEARS * MONTHS_PER_YEAR;
   537→
   538→        expect(expectedProjections).toBe(120);
   539→      });
   540→
   541→      test('should round projected mileage to nearest km', () => {
   542→        const currentKm = 100000;
   543→        const avgDailyKm = 285.7; // Non-integer average
   544→        const days = 30;
   545→
   546→        const projected = currentKm + avgDailyKm * days;
   547→        const rounded = Math.round(projected);
   548→
   549→        expect(rounded).toBe(108571);
   550→      });
   551→    });
   552→
   553→    describe('Baseline Supersession', () => {
   554→      test('should supersede previous baseline when publishing new one', () => {
   555→        interface Baseline {
   556→          id: string;
   557→          version: string;
   558→          status: BaselineStatus;
   559→          supersededBy: string | null;
   560→        }
   561→
   562→        const supersede = (
   563→          current: Baseline,
   564→          newBaseline: { id: string }
   565→        ): Baseline => ({
   566→          ...current,
   567→          status: 'SUPERSEDED',
   568→          supersededBy: newBaseline.id,
   569→        });
   570→
   571→        const oldBaseline: Baseline = {
   572→          id: 'baseline-old',
   573→          version: 'v1.0',
   574→          status: 'PUBLISHED',
   575→          supersededBy: null,
   576→        };
   577→
   578→        const updated = supersede(oldBaseline, { id: 'baseline-new' });
   579→
   580→        expect(updated.status).toBe('SUPERSEDED');
   581→        expect(updated.supersededBy).toBe('baseline-new');
   582→      });
   583→
   584→      test('should only supersede PUBLISHED baselines', () => {
   585→        const canSupersede = (status: BaselineStatus) => status === 'PUBLISHED';
   586→
   587→        expect(canSupersede('PUBLISHED')).toBe(true);
   588→        expect(canSupersede('DRAFT')).toBe(false);
   589→        expect(canSupersede('SUPERSEDED')).toBe(false);
   590→        expect(canSupersede('ARCHIVED')).toBe(false);
   591→      });
   592→    });
   593→  });
   594→
   595→  describe('Pagination', () => {
   596→    test('should calculate total pages correctly', () => {
   597→      const calculateTotalPages = (total: number, pageSize: number) =>
   598→        Math.ceil(total / pageSize);
   599→
   600→      expect(calculateTotalPages(100, 20)).toBe(5);
   601→      expect(calculateTotalPages(101, 20)).toBe(6);
   602→      expect(calculateTotalPages(20, 20)).toBe(1);
   603→      expect(calculateTotalPages(0, 20)).toBe(0);
   604→    });
   605→
   606→    test('should calculate offset correctly', () => {
   607→      const calculateOffset = (page: number, pageSize: number) =>
   608→        (page - 1) * pageSize;
   609→
   610→      expect(calculateOffset(1, 20)).toBe(0);
   611→      expect(calculateOffset(2, 20)).toBe(20);
   612→      expect(calculateOffset(3, 20)).toBe(40);
   613→      expect(calculateOffset(1, 50)).toBe(0);
   614→      expect(calculateOffset(2, 50)).toBe(50);
   615→    });
   616→
   617→    test('should use default pagination when not specified', () => {
   618→      const DEFAULT_PAGE = 1;
   619→      const DEFAULT_PAGE_SIZE = 20;
   620→
   621→      const getPage = (options?: { page?: number }) =>
   622→        options?.page ?? DEFAULT_PAGE;
   623→      const getPageSize = (options?: { pageSize?: number }) =>
   624→        options?.pageSize ?? DEFAULT_PAGE_SIZE;
   625→
   626→      expect(getPage()).toBe(1);
   627→      expect(getPage({})).toBe(1);
   628→      expect(getPage({ page: 5 })).toBe(5);
   629→
   630→      expect(getPageSize()).toBe(20);
   631→      expect(getPageSize({})).toBe(20);
   632→      expect(getPageSize({ pageSize: 50 })).toBe(50);
   633→    });
   634→  });
   635→
   636→  describe('Error Handling', () => {
   637→    test('NotFoundError should be used for missing baselines', () => {
   638→      const error = new NotFoundError('Baseline not found: baseline-123');
   639→      expect(error.message).toBe('Baseline not found: baseline-123');
   640→      expect(error.code).toBe('BUS_010'); // MMS error code for NotFoundError
   641→    });
   642→
   643→    test('ValidationError should be used for invalid publish requests', () => {
   644→      const conflicts = [{ type: 'OVERDUE_PM', description: 'PM overdue' }];
   645→      const error = new ValidationError(
   646→        'Cannot publish baseline with critical conflicts',
   647→        { context: { conflicts } }
   648→      );
   649→      expect(error.message).toBe('Cannot publish baseline with critical conflicts');
   650→      expect(error.code).toBe('BUS_001'); // MMS error code for ValidationError
   651→      expect(error.context?.conflicts).toBeDefined();
   652→    });
   653→
   654→    test('BusinessRuleError should be used for archive violations', () => {
   655→      const error = new BusinessRuleError(
   656→        'Cannot archive published baseline. Publish a new baseline first to supersede it.'
   657→      );
   658→      expect(error.message).toContain('Cannot archive published baseline');
   659→    });
   660→  });
   661→
   662→  describe('Audit Requirements', () => {
   663→    test('should log PUBLISH action for new baselines', () => {
   664→      const auditAction = 'PUBLISH';
   665→      expect(auditAction).toBe('PUBLISH');
   666→    });
   667→
   668→    test('should log UPDATE action for archiving', () => {
   669→      const auditAction = 'UPDATE';
   670→      expect(auditAction).toBe('UPDATE');
   671→    });
   672→
   673→    test('should include compliance flags for planning actions', () => {
   674→      const complianceFlags = ['PLANNING'];
   675→      expect(complianceFlags).toContain('PLANNING');
   676→    });
   677→
   678→    test('should capture old and new values for status changes', () => {
   679→      const oldValues = { status: 'PUBLISHED' };
   680→      const newValues = { status: 'ARCHIVED' };
   681→
   682→      expect(oldValues.status).toBe('PUBLISHED');
   683→      expect(newValues.status).toBe('ARCHIVED');
   684→    });
   685→  });
   686→
   687→  describe('Snapshot Rules', () => {
   688→    test('should only snapshot SCHEDULED and IN_PROGRESS PMs', () => {
   689→      const validStatuses = ['SCHEDULED', 'IN_PROGRESS'];
   690→      const allStatuses = [
   691→        'SCHEDULED',
   692→        'IN_PROGRESS',
   693→        'COMPLETED',
   694→        'CANCELLED',
   695→        'DEFERRED',
   696→      ];
   697→
   698→      const toSnapshot = allStatuses.filter((s) => validStatuses.includes(s));
   699→      expect(toSnapshot).toEqual(['SCHEDULED', 'IN_PROGRESS']);
   700→    });
   701→
   702→    test('should only snapshot production PMs (scenarioId IS NULL)', () => {
   703→      interface PM { id: string; scenarioId: string | null; }
   704→
   705→      const pms: PM[] = [
   706→        { id: 'pm-1', scenarioId: null }, // Production
   707→        { id: 'pm-2', scenarioId: 'scenario-1' }, // Scenario
   708→        { id: 'pm-3', scenarioId: null }, // Production
   709→      ];
   710→
   711→      const productionPms = pms.filter((pm) => pm.scenarioId === null);
   712→      expect(productionPms).toHaveLength(2);
   713→    });
   714→
   715→    test('should only snapshot future PMs (targetDate >= today)', () => {
   716→      interface PM { id: string; targetDate: Date; }
   717→      const today = new Date('2026-01-20');
   718→
   719→      const pms: PM[] = [
   720→        { id: 'pm-1', targetDate: new Date('2026-01-15') }, // Past
   721→        { id: 'pm-2', targetDate: new Date('2026-01-20') }, // Today
   722→        { id: 'pm-3', targetDate: new Date('2026-02-01') }, // Future
   723→      ];
   724→
   725→      const futurePms = pms.filter((pm) => pm.targetDate >= today);
   726→      expect(futurePms).toHaveLength(2);
