   729→
   730→  describe('Horizon Calculation', () => {
   731→    test('should default to 10-year horizon', () => {
   732→      const DEFAULT_HORIZON_YEARS = 10;
   733→      const baselineDate = new Date('2026-01-20');
   734→      const horizonEnd = new Date(baselineDate);
