/**
 * MMS Baseline Service Unit Tests
 *
 * Tests for the Baseline Service covering:
 * - Service initialization and singleton pattern
 * - Baseline version management
 * - Plan validation for publishing
 * - Mileage projection calculations
 * - Baseline lifecycle management
 * - Pagination and filtering
 *
 * Note: These tests use Bun's test framework and document expected behavior.
 * Integration tests with actual database should be in a separate test suite.
 *
 * @see src/services/baseline.ts
 */

import { describe, test, expect } from 'bun:test';
import {
  BaselineService,
  getBaselineService,
  type BaselineStatus,
  type BaselineListFilters,
  type BaselinePaginationOptions,
  type PublishBaselineRequest,
  type PlanConflict,
  type PlanWarning,
  type PlanValidationResult,
  type BaselineSummary,
} from './baseline';
import {
  NotFoundError,
  ValidationError,
  BusinessRuleError,
} from '../lib/errors';

describe('BaselineService', () => {
  describe('Initialization', () => {
    test('should create a BaselineService instance', () => {
      const service = new BaselineService();
      expect(service).toBeDefined();
      expect(service).toBeInstanceOf(BaselineService);
    });

    test('should return singleton instance via getBaselineService', () => {
      const instance1 = getBaselineService();
      const instance2 = getBaselineService();
      expect(instance1).toBe(instance2);
    });
  });

  describe('Type Definitions', () => {
    describe('BaselineStatus', () => {
      test('should support all baseline status values', () => {
        const statuses: BaselineStatus[] = ['DRAFT', 'PUBLISHED', 'SUPERSEDED', 'ARCHIVED'];
        expect(statuses).toHaveLength(4);
        expect(statuses).toContain('DRAFT');
        expect(statuses).toContain('PUBLISHED');
        expect(statuses).toContain('SUPERSEDED');
        expect(statuses).toContain('ARCHIVED');
      });
    });

    describe('BaselineListFilters', () => {
      test('should support single status filter', () => {
        const filters: BaselineListFilters = {
          status: 'PUBLISHED',
        };
        expect(filters.status).toBe('PUBLISHED');
      });

      test('should support multiple status filters', () => {
        const filters: BaselineListFilters = {
          status: ['PUBLISHED', 'SUPERSEDED'],
        };
        expect(Array.isArray(filters.status)).toBe(true);
        expect(filters.status).toContain('PUBLISHED');
        expect(filters.status).toContain('SUPERSEDED');
      });

      test('should support date range filters', () => {
        const filters: BaselineListFilters = {
          fromDate: new Date('2026-01-01'),
          toDate: new Date('2026-12-31'),
        };
        expect(filters.fromDate).toBeDefined();
        expect(filters.toDate).toBeDefined();
      });

      test('should support createdBy filter', () => {
        const filters: BaselineListFilters = {
          createdBy: 'user-123',
        };
        expect(filters.createdBy).toBe('user-123');
      });
    });

    describe('BaselinePaginationOptions', () => {
      test('should have sensible defaults when empty', () => {
        const pagination: BaselinePaginationOptions = {};
        expect(pagination.page).toBeUndefined();
        expect(pagination.pageSize).toBeUndefined();
        expect(pagination.sortBy).toBeUndefined();
        expect(pagination.sortOrder).toBeUndefined();
      });

      test('should support all sort options', () => {
        const pagination: BaselinePaginationOptions = {
          page: 1,
          pageSize: 20,
          sortBy: 'baselineDate',
          sortOrder: 'desc',
        };
        expect(pagination.sortBy).toBe('baselineDate');
        expect(pagination.sortOrder).toBe('desc');
      });

      test('should support version sorting', () => {
        const pagination: BaselinePaginationOptions = {
          sortBy: 'version',
          sortOrder: 'asc',
        };
        expect(pagination.sortBy).toBe('version');
      });

      test('should support createdAt sorting', () => {
        const pagination: BaselinePaginationOptions = {
          sortBy: 'createdAt',
          sortOrder: 'desc',
        };
        expect(pagination.sortBy).toBe('createdAt');
      });
    });

    describe('PublishBaselineRequest', () => {
      test('should require name and userId', () => {
        const request: PublishBaselineRequest = {
          name: 'Q1 2026 Plan',
          userId: 'user-123',
        };
        expect(request.name).toBe('Q1 2026 Plan');
        expect(request.userId).toBe('user-123');
      });

      test('should support optional description', () => {
        const request: PublishBaselineRequest = {
          name: 'Q1 2026 Plan',
          userId: 'user-123',
          description: 'Quarterly maintenance baseline',
        };
        expect(request.description).toBe('Quarterly maintenance baseline');
      });

      test('should support optional horizonYears', () => {
        const request: PublishBaselineRequest = {
          name: 'Long-term Plan',
          userId: 'user-123',
          horizonYears: 12,
        };
        expect(request.horizonYears).toBe(12);
      });
    });

    describe('PlanConflict', () => {
      test('should support OVERDUE_PM conflict type', () => {
        const conflict: PlanConflict = {
          type: 'OVERDUE_PM',
          trainId: 'train-123',
          trainNumber: 'T001',
          pmScheduleId: 'pm-456',
          description: 'PM is overdue (compliance window ended 2026-01-15)',
        };
        expect(conflict.type).toBe('OVERDUE_PM');
        expect(conflict.trainId).toBe('train-123');
        expect(conflict.pmScheduleId).toBe('pm-456');
      });

      test('should support TRACK_CONFLICT conflict type', () => {
        const conflict: PlanConflict = {
          type: 'TRACK_CONFLICT',
          description: 'Track A1 is double-booked on 2026-02-01',
        };
        expect(conflict.type).toBe('TRACK_CONFLICT');
      });

      test('should support MATERIAL_BLOCK conflict type', () => {
        const conflict: PlanConflict = {
          type: 'MATERIAL_BLOCK',
          trainId: 'train-123',
          trainNumber: 'T002',
          pmScheduleId: 'pm-789',
          description: 'Missing critical material: Brake Pads (BRK-001)',
        };
        expect(conflict.type).toBe('MATERIAL_BLOCK');
      });

      test('should support GROUNDED_TRAIN conflict type', () => {
        const conflict: PlanConflict = {
          type: 'GROUNDED_TRAIN',
          trainId: 'train-456',
          trainNumber: 'T003',
          pmScheduleId: 'pm-101',
          description: 'Train is grounded but has scheduled PMs',
        };
        expect(conflict.type).toBe('GROUNDED_TRAIN');
      });
    });

    describe('PlanWarning', () => {
      test('should support APPROACHING_COMPLIANCE warning type', () => {
        const warning: PlanWarning = {
          type: 'APPROACHING_COMPLIANCE',
          trainId: 'train-123',
          trainNumber: 'T001',
          description: 'PM C4 compliance window ends in 5 days',
        };
        expect(warning.type).toBe('APPROACHING_COMPLIANCE');
      });

      test('should support LOW_MATERIAL warning type', () => {
        const warning: PlanWarning = {
          type: 'LOW_MATERIAL',
          description: 'Part BRK-001 has only 5 units (minimum 10)',
        };
        expect(warning.type).toBe('LOW_MATERIAL');
      });

      test('should support HIGH_UTILIZATION warning type', () => {
        const warning: PlanWarning = {
          type: 'HIGH_UTILIZATION',
          description: 'Track A1 utilization at 95% for next 2 weeks',
        };
        expect(warning.type).toBe('HIGH_UTILIZATION');
      });
    });

    describe('PlanValidationResult', () => {
      test('should indicate valid plan when no conflicts', () => {
        const result: PlanValidationResult = {
          valid: true,
          conflicts: [],
          warnings: [],
        };
        expect(result.valid).toBe(true);
        expect(result.conflicts).toHaveLength(0);
      });

      test('should indicate invalid plan when conflicts exist', () => {
        const result: PlanValidationResult = {
          valid: false,
          conflicts: [
            {
              type: 'OVERDUE_PM',
              trainId: 'train-123',
              trainNumber: 'T001',
              description: 'PM is overdue',
            },
          ],
          warnings: [],
        };
        expect(result.valid).toBe(false);
        expect(result.conflicts).toHaveLength(1);
      });

      test('should allow valid plan with warnings', () => {
        const result: PlanValidationResult = {
          valid: true,
          conflicts: [],
          warnings: [
            {
              type: 'LOW_MATERIAL',
              description: 'Low material stock',
            },
          ],
        };
        expect(result.valid).toBe(true);
        expect(result.warnings).toHaveLength(1);
      });
    });

    describe('BaselineSummary', () => {
      test('should contain all summary fields', () => {
        const summary: BaselineSummary = {
          id: 'baseline-123',
          name: 'Q1 2026 Plan',
          version: 'v2.5',
          status: 'PUBLISHED',
          baselineDate: '2026-01-20',
          horizonEnd: '2036-01-20',
          fleetCount: 128,
          totalPmScheduled: 456,
          totalManhourProjected: '12500.50',
          createdAt: new Date(),
          publishedAt: new Date(),
        };
        expect(summary.id).toBe('baseline-123');
        expect(summary.version).toBe('v2.5');
        expect(summary.status).toBe('PUBLISHED');
        expect(summary.fleetCount).toBe(128);
      });

      test('should allow null values for metrics', () => {
        const summary: BaselineSummary = {
          id: 'baseline-draft',
          name: 'Draft Plan',
          version: 'v1.0',
          status: 'DRAFT',
          baselineDate: '2026-01-20',
          horizonEnd: '2036-01-20',
          fleetCount: null,
          totalPmScheduled: null,
          totalManhourProjected: null,
          createdAt: null,
          publishedAt: null,
        };
        expect(summary.fleetCount).toBeNull();
        expect(summary.totalPmScheduled).toBeNull();
      });
    });
  });

  describe('Business Rules', () => {
    describe('Version Incrementing', () => {
      // The incrementVersion function increments vMajor.Minor format
      const incrementVersion = (current: string | null): string => {
        if (!current) {
          return 'v1.0';
        }
        const match = current.match(/^v?(\d+)\.(\d+)$/);
        if (!match) {
          return 'v1.0';
        }
        const major = parseInt(match[1], 10);
        const minor = parseInt(match[2], 10);
        if (minor >= 99) {
          return `v${major + 1}.0`;
        }
        return `v${major}.${minor + 1}`;
      };

      test('should start at v1.0 when no previous version', () => {
        expect(incrementVersion(null)).toBe('v1.0');
      });

      test('should increment minor version v1.0 -> v1.1', () => {
        expect(incrementVersion('v1.0')).toBe('v1.1');
      });

      test('should increment minor version v1.5 -> v1.6', () => {
        expect(incrementVersion('v1.5')).toBe('v1.6');
      });

      test('should increment minor version v2.10 -> v2.11', () => {
        expect(incrementVersion('v2.10')).toBe('v2.11');
      });

      test('should roll over to next major at v1.99 -> v2.0', () => {
        expect(incrementVersion('v1.99')).toBe('v2.0');
      });

      test('should roll over to next major at v5.99 -> v6.0', () => {
        expect(incrementVersion('v5.99')).toBe('v6.0');
      });

      test('should handle version without v prefix', () => {
        expect(incrementVersion('1.5')).toBe('v1.6');
      });

      test('should default to v1.0 for invalid format', () => {
        expect(incrementVersion('invalid')).toBe('v1.0');
        expect(incrementVersion('v1')).toBe('v1.0');
        expect(incrementVersion('1.2.3')).toBe('v1.0');
      });
    });

    describe('Baseline Lifecycle', () => {
      test('DRAFT baselines can transition to PUBLISHED', () => {
        // Draft -> Published is the normal publication flow
        const validTransitions: Record<BaselineStatus, BaselineStatus[]> = {
          DRAFT: ['PUBLISHED'],
          PUBLISHED: ['SUPERSEDED', 'ARCHIVED'],
          SUPERSEDED: ['ARCHIVED'],
          ARCHIVED: [],
        };
        expect(validTransitions['DRAFT']).toContain('PUBLISHED');
      });

      test('PUBLISHED baselines can be SUPERSEDED or ARCHIVED', () => {
        const validTransitions: Record<BaselineStatus, BaselineStatus[]> = {
          DRAFT: ['PUBLISHED'],
          PUBLISHED: ['SUPERSEDED', 'ARCHIVED'],
          SUPERSEDED: ['ARCHIVED'],
          ARCHIVED: [],
        };
        expect(validTransitions['PUBLISHED']).toContain('SUPERSEDED');
        expect(validTransitions['PUBLISHED']).toContain('ARCHIVED');
      });

      test('SUPERSEDED baselines can only be ARCHIVED', () => {
        const validTransitions: Record<BaselineStatus, BaselineStatus[]> = {
          DRAFT: ['PUBLISHED'],
          PUBLISHED: ['SUPERSEDED', 'ARCHIVED'],
          SUPERSEDED: ['ARCHIVED'],
          ARCHIVED: [],
        };
        expect(validTransitions['SUPERSEDED']).toEqual(['ARCHIVED']);
      });

      test('ARCHIVED baselines cannot transition', () => {
        const validTransitions: Record<BaselineStatus, BaselineStatus[]> = {
          DRAFT: ['PUBLISHED'],
          PUBLISHED: ['SUPERSEDED', 'ARCHIVED'],
          SUPERSEDED: ['ARCHIVED'],
          ARCHIVED: [],
        };
        expect(validTransitions['ARCHIVED']).toHaveLength(0);
      });
    });

    describe('Plan Validation Rules', () => {
      test('should fail validation if any PM is overdue', () => {
        const checkOverduePms = (pms: Array<{ constraintEnd: Date; status: string }>) => {
          const today = new Date();
          return pms.filter(
            (pm) => pm.status === 'SCHEDULED' && pm.constraintEnd < today
          );
        };

        const pms = [
          { constraintEnd: new Date('2025-12-31'), status: 'SCHEDULED' }, // Overdue
          { constraintEnd: new Date('2026-02-15'), status: 'SCHEDULED' }, // OK
        ];

        const overdue = checkOverduePms(pms);
        expect(overdue).toHaveLength(1);
      });

      test('should fail validation if grounded train has scheduled PMs', () => {
        interface Train { id: string; fitnessStatus: string; }
        interface PM { trainId: string; status: string; }

        const validate = (trains: Train[], pms: PM[]) => {
          const groundedTrainIds = trains
            .filter((t) => t.fitnessStatus === 'GROUNDED')
            .map((t) => t.id);

          return pms.filter(
            (pm) =>
              pm.status === 'SCHEDULED' && groundedTrainIds.includes(pm.trainId)
          );
        };

        const trains = [
          { id: 'train-1', fitnessStatus: 'FIT' },
          { id: 'train-2', fitnessStatus: 'GROUNDED' },
        ];

        const pms = [
          { trainId: 'train-1', status: 'SCHEDULED' },
          { trainId: 'train-2', status: 'SCHEDULED' }, // Invalid
        ];

        const invalid = validate(trains, pms);
        expect(invalid).toHaveLength(1);
        expect(invalid[0].trainId).toBe('train-2');
      });

      test('should allow publishing with warnings but no conflicts', () => {
        const canPublish = (result: PlanValidationResult) => result.valid;

        const resultWithWarnings: PlanValidationResult = {
          valid: true,
          conflicts: [],
          warnings: [{ type: 'LOW_MATERIAL', description: 'Low stock' }],
        };

        expect(canPublish(resultWithWarnings)).toBe(true);
      });

      test('should not allow publishing with conflicts', () => {
        const canPublish = (result: PlanValidationResult) => result.valid;

        const resultWithConflicts: PlanValidationResult = {
          valid: false,
          conflicts: [{ type: 'OVERDUE_PM', description: 'PM overdue' }],
          warnings: [],
        };

        expect(canPublish(resultWithConflicts)).toBe(false);
      });
    });

    describe('Mileage Projection Rules', () => {
      test('should use 30-day average when history available', () => {
        const dailyReadings = [300, 280, 320, 290, 310, 305, 295];
        const avg = dailyReadings.reduce((a, b) => a + b, 0) / dailyReadings.length;

        expect(avg).toBeCloseTo(300);
      });

      test('should use default 150km when no history', () => {
        const DEFAULT_DAILY_KM = 150;
        const dailyReadings: number[] = [];

        const avgDailyKm =
          dailyReadings.length > 0
            ? dailyReadings.reduce((a, b) => a + b, 0) / dailyReadings.length
            : DEFAULT_DAILY_KM;

        expect(avgDailyKm).toBe(150);
      });

      test('should project monthly cumulative mileage', () => {
        const currentKm = 100000;
        const avgDailyKm = 300;
        const months = 3;

        // Monthly projections with explicit type
        const projections: Array<{ month: number; km: number }> = [];
        let cumulative = currentKm;

        for (let m = 1; m <= months; m++) {
          cumulative += avgDailyKm * 30;
          projections.push({ month: m, km: cumulative });
        }

        expect(projections).toHaveLength(3);
        expect(projections[0].km).toBe(109000); // 100000 + 9000
        expect(projections[1].km).toBe(118000); // 100000 + 18000
        expect(projections[2].km).toBe(127000); // 100000 + 27000
      });

      test('should project for default 10 years (120 months)', () => {
        const DEFAULT_HORIZON_YEARS = 10;
        const MONTHS_PER_YEAR = 12;
        const expectedProjections = DEFAULT_HORIZON_YEARS * MONTHS_PER_YEAR;

        expect(expectedProjections).toBe(120);
      });

      test('should round projected mileage to nearest km', () => {
        const currentKm = 100000;
        const avgDailyKm = 285.7; // Non-integer average
        const days = 30;

        const projected = currentKm + avgDailyKm * days;
        const rounded = Math.round(projected);

        expect(rounded).toBe(108571);
      });
    });

    describe('Baseline Supersession', () => {
      test('should supersede previous baseline when publishing new one', () => {
        interface Baseline {
          id: string;
          version: string;
          status: BaselineStatus;
          supersededBy: string | null;
        }

        const supersede = (
          current: Baseline,
          newBaseline: { id: string }
        ): Baseline => ({
          ...current,
          status: 'SUPERSEDED',
          supersededBy: newBaseline.id,
        });

        const oldBaseline: Baseline = {
          id: 'baseline-old',
          version: 'v1.0',
          status: 'PUBLISHED',
          supersededBy: null,
        };

        const updated = supersede(oldBaseline, { id: 'baseline-new' });

        expect(updated.status).toBe('SUPERSEDED');
        expect(updated.supersededBy).toBe('baseline-new');
      });

      test('should only supersede PUBLISHED baselines', () => {
        const canSupersede = (status: BaselineStatus) => status === 'PUBLISHED';

        expect(canSupersede('PUBLISHED')).toBe(true);
        expect(canSupersede('DRAFT')).toBe(false);
        expect(canSupersede('SUPERSEDED')).toBe(false);
        expect(canSupersede('ARCHIVED')).toBe(false);
      });
    });
  });

  describe('Pagination', () => {
    test('should calculate total pages correctly', () => {
      const calculateTotalPages = (total: number, pageSize: number) =>
        Math.ceil(total / pageSize);

      expect(calculateTotalPages(100, 20)).toBe(5);
      expect(calculateTotalPages(101, 20)).toBe(6);
      expect(calculateTotalPages(20, 20)).toBe(1);
      expect(calculateTotalPages(0, 20)).toBe(0);
    });

    test('should calculate offset correctly', () => {
      const calculateOffset = (page: number, pageSize: number) =>
        (page - 1) * pageSize;

      expect(calculateOffset(1, 20)).toBe(0);
      expect(calculateOffset(2, 20)).toBe(20);
      expect(calculateOffset(3, 20)).toBe(40);
      expect(calculateOffset(1, 50)).toBe(0);
      expect(calculateOffset(2, 50)).toBe(50);
    });

    test('should use default pagination when not specified', () => {
      const DEFAULT_PAGE = 1;
      const DEFAULT_PAGE_SIZE = 20;

      const getPage = (options?: { page?: number }) =>
        options?.page ?? DEFAULT_PAGE;
      const getPageSize = (options?: { pageSize?: number }) =>
        options?.pageSize ?? DEFAULT_PAGE_SIZE;

      expect(getPage()).toBe(1);
      expect(getPage({})).toBe(1);
      expect(getPage({ page: 5 })).toBe(5);

      expect(getPageSize()).toBe(20);
      expect(getPageSize({})).toBe(20);
      expect(getPageSize({ pageSize: 50 })).toBe(50);
    });
  });

  describe('Error Handling', () => {
    test('NotFoundError should be used for missing baselines', () => {
      const error = new NotFoundError('Baseline not found: baseline-123');
      expect(error.message).toBe('Baseline not found: baseline-123');
      expect(error.code).toBe('BUS_010'); // MMS error code for NotFoundError
    });

    test('ValidationError should be used for invalid publish requests', () => {
      const conflicts = [{ type: 'OVERDUE_PM', description: 'PM overdue' }];
      const error = new ValidationError(
        'Cannot publish baseline with critical conflicts',
        { context: { conflicts } }
      );
      expect(error.message).toBe('Cannot publish baseline with critical conflicts');
      expect(error.code).toBe('BUS_001'); // MMS error code for ValidationError
      expect(error.context?.conflicts).toBeDefined();
    });

    test('BusinessRuleError should be used for archive violations', () => {
      const error = new BusinessRuleError(
        'Cannot archive published baseline. Publish a new baseline first to supersede it.'
      );
      expect(error.message).toContain('Cannot archive published baseline');
    });
  });

  describe('Audit Requirements', () => {
    test('should log PUBLISH action for new baselines', () => {
      const auditAction = 'PUBLISH';
      expect(auditAction).toBe('PUBLISH');
    });

    test('should log UPDATE action for archiving', () => {
      const auditAction = 'UPDATE';
      expect(auditAction).toBe('UPDATE');
    });

    test('should include compliance flags for planning actions', () => {
      const complianceFlags = ['PLANNING'];
      expect(complianceFlags).toContain('PLANNING');
    });

    test('should capture old and new values for status changes', () => {
      const oldValues = { status: 'PUBLISHED' };
      const newValues = { status: 'ARCHIVED' };

      expect(oldValues.status).toBe('PUBLISHED');
      expect(newValues.status).toBe('ARCHIVED');
    });
  });

  describe('Snapshot Rules', () => {
    test('should only snapshot SCHEDULED and IN_PROGRESS PMs', () => {
      const validStatuses = ['SCHEDULED', 'IN_PROGRESS'];
      const allStatuses = [
        'SCHEDULED',
        'IN_PROGRESS',
        'COMPLETED',
        'CANCELLED',
        'DEFERRED',
      ];

      const toSnapshot = allStatuses.filter((s) => validStatuses.includes(s));
      expect(toSnapshot).toEqual(['SCHEDULED', 'IN_PROGRESS']);
    });

    test('should only snapshot production PMs (scenarioId IS NULL)', () => {
      interface PM { id: string; scenarioId: string | null; }

      const pms: PM[] = [
        { id: 'pm-1', scenarioId: null }, // Production
        { id: 'pm-2', scenarioId: 'scenario-1' }, // Scenario
        { id: 'pm-3', scenarioId: null }, // Production
      ];

      const productionPms = pms.filter((pm) => pm.scenarioId === null);
      expect(productionPms).toHaveLength(2);
    });

    test('should only snapshot future PMs (targetDate >= today)', () => {
      interface PM { id: string; targetDate: Date; }
      const today = new Date('2026-01-20');

      const pms: PM[] = [
        { id: 'pm-1', targetDate: new Date('2026-01-15') }, // Past
        { id: 'pm-2', targetDate: new Date('2026-01-20') }, // Today
        { id: 'pm-3', targetDate: new Date('2026-02-01') }, // Future
      ];

      const futurePms = pms.filter((pm) => pm.targetDate >= today);
      expect(futurePms).toHaveLength(2);
    });
  });

  describe('Horizon Calculation', () => {
    test('should default to 10-year horizon', () => {
      const DEFAULT_HORIZON_YEARS = 10;
      const baselineDate = new Date('2026-01-20');
      const horizonEnd = new Date(baselineDate);
      horizonEnd.setFullYear(horizonEnd.getFullYear() + DEFAULT_HORIZON_YEARS);

      expect(horizonEnd.getFullYear()).toBe(2036);
    });

    test('should support custom horizon years', () => {
      const customHorizonYears = 12;
      const baselineDate = new Date('2026-01-20');
      const horizonEnd = new Date(baselineDate);
      horizonEnd.setFullYear(horizonEnd.getFullYear() + customHorizonYears);

      expect(horizonEnd.getFullYear()).toBe(2038);
    });
  });
});

