/**
 * MMS Database Schema
 *
 * Central export for all Drizzle schema definitions.
 * This file re-exports all tables, relations, and enums from domain-specific files.
 *
 * Domain Organization:
 * - enums.ts: PostgreSQL enum types
 * - core-fleet.ts: Depots, fleets, trains, routes, tracks
 * - users.ts: Users, roles, sessions
 * - operational-constraints.ts: Service demand, route utilization, unavailability, compatibility
 * - track-capabilities.ts: Track capabilities, PM requirements, baseline assumptions
 * - pm-management.ts: PM types, material requirements, PM schedule
 * - mileage-tracking.ts: Meter events, mileage readings
 * - component-tracking.ts: Train components, installations, component PM tracking
 * - material-management.ts: Inventory positions, material reservations
 * - manhour-planning.ts: Man-hour capacity, projections, adjustments
 * - baseline-drift.ts: Plan baselines, baseline snapshots, drift analysis
 * - scenarios.ts: Scenarios, deltas, comparisons
 * - costing.ts: Labor rates, material costs, cost baselines
 * - audit.ts: PM schedule history, audit log
 *
 * @see specs/003-database-schema.md for full schema specification
 */

// ============================================================================
// Enums
// ============================================================================
export * from './enums';

// ============================================================================
// Core Fleet Domain
// ============================================================================
export {
  depots,
  depotsRelations,
  fleets,
  fleetsRelations,
  routes,
  tracks,
  tracksRelations,
  trains,
  trainsRelations,
} from './core-fleet';

// ============================================================================
// Users & Authentication
// ============================================================================
export { roles, sessions, sessionsRelations, users, usersRelations } from './users';

// ============================================================================
// Operational Constraints (v2.1)
// ============================================================================
export {
  routeUtilizationProfiles,
  routeUtilizationProfilesRelations,
  serviceDemand,
  serviceDemandRelations,
  trainRouteCompatibility,
  trainRouteCompatibilityRelations,
  unavailabilityEvents,
  unavailabilityEventsRelations,
} from './operational-constraints';

// ============================================================================
// Track Capabilities (v2.1)
// ============================================================================
export {
  pmBaselineAssumptions,
  pmBaselineAssumptionsRelations,
  pmCapabilityRequirements,
  pmCapabilityRequirementsRelations,
  trackCapabilities,
  trackCapabilitiesRelations,
} from './track-capabilities';

// ============================================================================
// PM Management
// ============================================================================
export {
  pmMaterialRequirements,
  pmMaterialRequirementsRelations,
  pmSchedule,
  pmScheduleRelations,
  pmTypes,
  pmTypesRelations,
} from './pm-management';

// ============================================================================
// Mileage Tracking
// ============================================================================
export {
  meterEvents,
  meterEventsRelations,
  mileageReadings,
  mileageReadingsRelations,
} from './mileage-tracking';

// ============================================================================
// Component Tracking
// ============================================================================
export {
  componentInstallations,
  componentInstallationsRelations,
  componentPmTracking,
  componentPmTrackingRelations,
  trainComponents,
  trainComponentsRelations,
} from './component-tracking';

// ============================================================================
// Material Management
// ============================================================================
export {
  inventoryPositions,
  inventoryPositionsRelations,
  materialReservations,
  materialReservationsRelations,
} from './material-management';

// ============================================================================
// Man-hour Planning
// ============================================================================
export {
  manhourAdjustments,
  manhourAdjustmentsRelations,
  manhourCapacity,
  manhourCapacityRelations,
  manhourProjections,
  manhourProjectionsRelations,
} from './manhour-planning';

// ============================================================================
// Baseline & Drift
// ============================================================================
export {
  baselineMileageProjection,
  baselineMileageProjectionRelations,
  baselinePmSchedule,
  baselinePmScheduleRelations,
  driftAnalysis,
  driftAnalysisRelations,
  planBaselines,
  planBaselinesRelations,
} from './baseline-drift';

// ============================================================================
// Scenarios
// ============================================================================
export {
  scenarioComparisons,
  scenarioComparisonsRelations,
  scenarioDeltas,
  scenarioDeltasRelations,
  scenarios,
  scenariosRelations,
} from './scenarios';

// ============================================================================
// Costing
// ============================================================================
export {
  costBaselines,
  costBaselinesRelations,
  laborRates,
  laborRatesRelations,
  materialCosts,
} from './costing';

// ============================================================================
// Audit
// ============================================================================
export {
  auditLog,
  auditLogRelations,
  pmScheduleHistory,
  pmScheduleHistoryRelations,
} from './audit';

// ============================================================================
// Type Exports for Application Use
// ============================================================================
import type { InferInsertModel, InferSelectModel } from 'drizzle-orm';

// Core Fleet
import { depots, fleets, routes, tracks, trains } from './core-fleet';
export type Depot = InferSelectModel<typeof depots>;
export type NewDepot = InferInsertModel<typeof depots>;
export type Fleet = InferSelectModel<typeof fleets>;
export type NewFleet = InferInsertModel<typeof fleets>;
export type Train = InferSelectModel<typeof trains>;
export type NewTrain = InferInsertModel<typeof trains>;
export type Route = InferSelectModel<typeof routes>;
export type NewRoute = InferInsertModel<typeof routes>;
export type Track = InferSelectModel<typeof tracks>;
export type NewTrack = InferInsertModel<typeof tracks>;

// Users
import { roles, sessions, users } from './users';
export type User = InferSelectModel<typeof users>;
export type NewUser = InferInsertModel<typeof users>;
export type Role = InferSelectModel<typeof roles>;
export type NewRole = InferInsertModel<typeof roles>;
export type Session = InferSelectModel<typeof sessions>;
export type NewSession = InferInsertModel<typeof sessions>;

// Operational Constraints
import {
  routeUtilizationProfiles,
  serviceDemand,
  trainRouteCompatibility,
  unavailabilityEvents,
} from './operational-constraints';
export type ServiceDemand = InferSelectModel<typeof serviceDemand>;
export type NewServiceDemand = InferInsertModel<typeof serviceDemand>;
export type RouteUtilizationProfile = InferSelectModel<typeof routeUtilizationProfiles>;
export type NewRouteUtilizationProfile = InferInsertModel<typeof routeUtilizationProfiles>;
export type UnavailabilityEvent = InferSelectModel<typeof unavailabilityEvents>;
export type NewUnavailabilityEvent = InferInsertModel<typeof unavailabilityEvents>;
export type TrainRouteCompatibility = InferSelectModel<typeof trainRouteCompatibility>;
export type NewTrainRouteCompatibility = InferInsertModel<typeof trainRouteCompatibility>;

// Track Capabilities
import {
  pmBaselineAssumptions,
  pmCapabilityRequirements,
  trackCapabilities,
} from './track-capabilities';
export type TrackCapability = InferSelectModel<typeof trackCapabilities>;
export type NewTrackCapability = InferInsertModel<typeof trackCapabilities>;
export type PmCapabilityRequirement = InferSelectModel<typeof pmCapabilityRequirements>;
export type NewPmCapabilityRequirement = InferInsertModel<typeof pmCapabilityRequirements>;
export type PmBaselineAssumption = InferSelectModel<typeof pmBaselineAssumptions>;
